package com.hospital.management.controller.schedule;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.DoctorScheduleServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.util.*;
@WebServlet("/schedules")public class DoctorScheduleListServlet extends HttpServlet{private final DoctorScheduleService service;public DoctorScheduleListServlet(){this(new DoctorScheduleServiceImpl());}public DoctorScheduleListServlet(DoctorScheduleService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{AuthenticatedUser u=ScheduleRequest.user(q);Long doctor=ScheduleRequest.id(q.getParameter("doctorId"));if("DOCTOR".equals(u.getRoleName())){Optional<Doctor>d=service.getOwnDoctor(u);if(d.isEmpty()){r.sendError(403);return;}doctor=d.get().getDoctorId();q.setAttribute("ownDoctor",d.get());}Long dep=ScheduleRequest.id(q.getParameter("departmentId"));String day=day(q.getParameter("dayOfWeek"));Boolean av=bool(q.getParameter("available"));PageRequest p=new PageRequest(num(q.getParameter("page"),1),num(q.getParameter("size"),10),q.getParameter("search"));q.setAttribute("schedulePage",service.listSchedules(p,doctor,dep,day,av));q.setAttribute("doctors",service.getActiveDoctors());q.setAttribute("doctorId",doctor);q.setAttribute("departmentId",dep);q.setAttribute("dayOfWeek",day);q.setAttribute("available",av);q.setAttribute("search",p.getSearchTerm());q.setAttribute("message",q.getParameter("message"));q.setAttribute("error",q.getParameter("error"));q.getRequestDispatcher("/WEB-INF/views/schedules/list.jsp").forward(q,r);}private int num(String s,int d){try{return Integer.parseInt(s);}catch(Exception e){return d;}}private String day(String s){try{return java.time.DayOfWeek.valueOf(s).name();}catch(Exception e){return null;}}private Boolean bool(String s){return"true".equals(s)?true:"false".equals(s)?false:null;}}
